for (const exam of Object.values(QUESTION_DATA["blok-ii-3"].exams)) {
  for (const type of Object.values(exam.types)) {
    for (const questions of Object.values(type.years)) {
      for (const question of questions) {
        const lectureNumber = LECTURE_NUMBERS.get(question.lecture);
        if (!lectureNumber) continue;

        const lectureHeading = `Lecture ${lectureNumber} - ${question.lecture}`;
        const explanation = question.explanation
          .replace(/^Lecture \d+\s*[:\-]\s*[^\n]+\n\n/, "")
          .trimStart();

        question.lectureNumber = lectureNumber;
        question.explanation = `${lectureHeading}\n\n${explanation}`;
      }
    }
  }
}
